parameters.jsonBody:
={
  "message": "{{ $json.body.message }}",
  "conversation_id": "{{ $json.body.conversation_id || '' }}",
  "model": "gemini",
  "system_prompt": "You are a helpful AI assistant with access to tools.",
  "tools": [
    {
      "name": "bash",
      "description": "Execute bash commands on the server",
      "parameters": {
        "type": "object",
        "properties": {
          "command": {"type": "string", "description": "The bash command to execute"}
        },
        "required": ["command"]
      }
    },
    {
      "name": "http_request",
      "description": "Make HTTP requests to external APIs",
      "parameters": {
        "type": "object",
        "properties": {
          "method": {"type": "string", "enum": ["GET", "POST", "PUT", "DELETE"]},
          "url": {"type": "string"},
          "data": {"type": "object"}
        },
        "required": ["method", "url"]
      }
    }
  ]
}

curl_examples.with_tools:
curl -X POST http://localhost:8765/chat \
  -H 'Content-Type: application/json' \
  -d '{
    "message": "What is the current date?",
    "model": "gemini",
    "tools": [
      {
        "name": "bash",
        "description": "Execute bash commands",
        "parameters": {"command": {"type": "string"}}
      }
    ]
  }'

n8n_code_node_example:
// Code Node example for n8n
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://localhost:8765/chat',
  body: {
    message: $input.first().json.message,
    conversation_id: $input.first().json.session_id || null,
    model: 'gemini',
    system_prompt: 'You are a helpful customer support agent.',
    tools: [
      {
        name: 'lookup_order',
        description: 'Look up order by ID',
        parameters: { order_id: { type: 'string' } },
        endpoint: 'http://localhost:3000/api/orders'
      }
    ]
  },
  json: true
});

return [{ json: response }];
